def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=np.float64)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 21):
            weight = 1 / (j ** 2)
            term = (ratio ** j) * weight
            if j % 3 == 0:
                term *= 1.5
            elif j % 2 == 0:
                term *= 1.2
            else:
                term *= 0.7
            score += term
            if score > 5:
                score *= 0.8
                break
        leftover = capacity - item
        if leftover < 0.05 * capacity:
            score *= 2.0
        elif leftover < 0.15 * capacity:
            score *= 1.5
        elif leftover < 0.3 * capacity:
            score *= 1.1
        else:
            score *= 0.85
        if i % 4 == 0:
            score *= 1.2
        elif i % 5 == 0:
            score *= 0.9
        if leftover > 0.5 * capacity:
            score -= 0.1 * leftover
        if score < 0:
            score = 0
        if score < 0.15:
            score += 0.05 * np.cos(i * item)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1.0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(n):
        if priorities[i] == np.inf:
            priorities[i] = max_priority * 4
    for i in range(n):
        if priorities[i] < 0.3:
            priorities[i] += 0.1 * np.sin(i * item * 0.5)
        if i % 2 == 1 and priorities[i] > 1.5:
            priorities[i] *= 0.95
    for i in range(n):
        for k in range(i+1, min(i+4, n)):
            diff = abs(priorities[i] - priorities[k])
            if diff < 0.05:
                priorities[i] *= 1.05
                priorities[k] *= 0.95
    return priorities
